# ═══════════════════════════════════════════════════════════════════
# run_pipeline.sh — Full Xu et al. neuron classification pipeline
#
# Backend: liuhaotian/llava-v1.5-7b (original LLaVA model)
#
# Chains:  gd → merge_gd → cn → merge_nc → prune / visualize / plot
# Keeps Python scripts separate; this script handles orchestration.
#
# Usage:
#   bash run_pipeline.sh                              # full pipeline, 32 GPUs
#   bash run_pipeline.sh --step gd                    # only generate descriptions
#   bash run_pipeline.sh --step cn                    # only classify (descriptions must exist)
#   bash run_pipeline.sh --step merge_gd              # merge generated description shards
#   bash run_pipeline.sh --step merge_nc              # merge per-shard classification results
#   bash run_pipeline.sh --step prune                 # ablation validation of taxonomy
#   bash run_pipeline.sh --step visualize             # generate Figure 3 visualizations (CPU only)
#   bash run_pipeline.sh --step visualize --viz-fig3  # reproduce exact Xu Figure 3 panels (a)-(f)
#   bash run_pipeline.sh --step visualize --viz-fig89 # reproduce Xu Figures 8 & 9 (two-sample)
#   bash run_pipeline.sh --step visualize --viz-supplementary  # reproduce Figures 15-17
#   bash run_pipeline.sh --step plot                          # generate Figures 5/6/7 + comparison charts
#   bash run_pipeline.sh --mode test                  # quick test (6 fig3 images, 2 layers, 1 GPU)
#   bash run_pipeline.sh --shards 16                  # use 16 GPUs
#   bash run_pipeline.sh --local                      # run locally (no bsub, no sharding)
#   bash run_pipeline.sh --queue waic-risk            # use waic-risk queue
#   bash run_pipeline.sh --suffix _v2                 # output to results/classification_v2
#   bash run_pipeline.sh --prune-images 200           # use 200 images for ablation
#   bash run_pipeline.sh --step prune --pope-path pope/coco_pope_random.json
#   bash run_pipeline.sh --step prune --pope-path pope/coco_pope_random.json \
#       --chair-ann-path /path/to/instances_val2014.json \
#       --pope-img-dir /path/to/val2014/
#
# GPU tiered escalation:
#   All jobs start at gmem=80G. If still PEND after 2 min, killed and
#   resubmitted at gmem=40G. After another 2 min → gmem=10G.
#   Override tiers: --gmem 80G,40G,10G   Override wait: --gmem-wait 120
#
# Idempotent: re-running skips jobs whose output already exists or
#             that are currently PEND/RUN in LSF.
#
# Examples:
#   bash run_pipeline.sh --mode test --local
#   bash run_pipeline.sh --shards 32
#   bash run_pipeline.sh --step cn --shards 32
# ═══════════════════════════════════════════════════════════════════

set -euo pipefail

# ── Defaults ──────────────────────────────────────────────────
QUEUE="waic-risk"
LOCAL=false
STEP="all"             # gd | cn | merge_gd | merge_nc | prune | visualize | plot | all
MODE="full"            # test | full
SHARDS=32              # GPUs
MODEL_TYPE="liuhaotian"    # model backend (liuhaotian/llava-v1.5-7b)
MODEL_PATH="liuhaotian/llava-v1.5-7b"  # HF Hub ID or local path to model weights
MODEL_NAME="llava-1.5-7b"  # must match --model default in $CLASSIFY_SCRIPT
OUT_SUFFIX_USER=""        # user-provided suffix for output dirs
CLASSIFY_SCRIPT="code/neuron_modality_statistical.py"  # classification script for step cn
ABLATION_SCRIPT="code/neuron_ablation_validate.py"      # ablation validation script for step prune
VIZ_SCRIPT="code/visualize_neuron_activations.py"        # Figure 3 visualization script for step visualize
PLOT_SCRIPT="code/plot_neuron_statistics.py"              # Figures 5/6/7 statistics charts for step plot
DESC_SUFFIX_USER=""        # suffix for description files (defaults to OUT_SUFFIX_USER)
OUTPUT_DIR_USER=""         # override classification output dir
PRUNE_IMAGES=100           # number of images for ablation validation
POPE_PATH="data/POPE/output/coco/coco_pope_random.json"   # path to POPE jsonl
CHAIR_ANN_PATH="data/annotations/instances_val2014.json"  # path to instances_val2014.json
POPE_IMG_DIR="data/val2014"                                 # path to COCO val images for POPE/CHAIR
CHAIR_NUM_IMAGES=500       # number of images for CHAIR evaluation
VIZ_FIG3=false             # if true, visualize step reproduces Xu Figure 3 panels
VIZ_FIG89=false            # if true, visualize step reproduces Xu Figures 8 & 9
VIZ_SUPPLEMENTARY=false    # if true, visualize step reproduces supplementary Figures 15-17

# ── Advanced ablation settings (8 approaches) ──
ABLATION_METHOD="zero"         # zero | mean | noise | clamp_high | clamp_low
ABLATION_CURVE=false           # if true, sweep top_n values (ablation curve)
ABLATION_TOP_N=""              # specific top_n value (empty = ablate all)
ABLATION_LAYER_RANGE=""        # e.g. "0-10" or "22-31" (empty = all layers)
ABLATION_CURVE_STEPS="100,500,1000,5000"  # comma-separated top_n values for curve
ABLATION_N_STATS=50            # reference images for mean/noise/clamp stats
ABLATION_RANKING="label"       # label | cett
ABLATION_N_CETT=30             # reference images for CETT computation
ABLATION_ALL=false             # if true, submit all approaches as parallel GPU jobs

# GPU memory tiers — escalate through tiers when jobs stay PEND
GPU_GMEM_TIERS=("20G")                # override with --gmem 40G,20G
GMEM_WAIT=120                          # seconds to wait before escalating (override with --gmem-wait)
GPU_RES_BASE="rusage[mem=49152] order[-gpu_maxfactor]"

# Dataset constants
N_TOTAL_IMAGES=23000
N_LAYERS=32

# ── Parse args ────────────────────────────────────────────────
while [[ $# -gt 0 ]]; do
    case $1 in
        --local)    LOCAL=true; shift ;;
        --step)     STEP="$2"; shift 2 ;;
        --mode)     MODE="$2"; shift 2 ;;
        --shards)   SHARDS="$2"; shift 2 ;;
        --queue)    QUEUE="$2"; shift 2 ;;
        --model-path) MODEL_PATH="$2"; shift 2 ;;
        --suffix)   OUT_SUFFIX_USER="$2"; shift 2 ;;
        --classify-script) CLASSIFY_SCRIPT="$2"; shift 2 ;;
        --ablation-script) ABLATION_SCRIPT="$2"; shift 2 ;;
        --desc-suffix) DESC_SUFFIX_USER="$2"; shift 2 ;;
        --output-dir) OUTPUT_DIR_USER="$2"; shift 2 ;;
        --prune-images) PRUNE_IMAGES="$2"; shift 2 ;;
        --pope-path) POPE_PATH="$2"; shift 2 ;;
        --chair-ann-path) CHAIR_ANN_PATH="$2"; shift 2 ;;
        --pope-img-dir) POPE_IMG_DIR="$2"; shift 2 ;;
        --chair-num-images) CHAIR_NUM_IMAGES="$2"; shift 2 ;;
        --viz-fig3) VIZ_FIG3=true; shift ;;
        --viz-fig89) VIZ_FIG89=true; shift ;;
        --viz-supplementary) VIZ_SUPPLEMENTARY=true; shift ;;
        --gmem)     IFS=',' read -ra GPU_GMEM_TIERS <<< "$2"; shift 2 ;;
        --gmem-wait) GMEM_WAIT="$2"; shift 2 ;;
        --ablation-method) ABLATION_METHOD="$2"; shift 2 ;;
        --ablation-curve) ABLATION_CURVE=true; shift ;;
        --ablation-top-n) ABLATION_TOP_N="$2"; shift 2 ;;
        --ablation-layer-range) ABLATION_LAYER_RANGE="$2"; shift 2 ;;
        --ablation-curve-steps) ABLATION_CURVE_STEPS="$2"; shift 2 ;;
        --ablation-n-stats) ABLATION_N_STATS="$2"; shift 2 ;;
        --ablation-ranking) ABLATION_RANKING="$2"; shift 2 ;;
        --ablation-n-cett) ABLATION_N_CETT="$2"; shift 2 ;;
        --ablation-all) ABLATION_ALL=true; shift ;;
        *)          echo "Unknown arg: $1"; exit 1 ;;
    esac
done

_SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
WORK_DIR="$(cd "$_SCRIPT_DIR/.." && pwd)"
cd "$WORK_DIR"
mkdir -p logs

# ── Shared HuggingFace cache (so all cluster nodes use the same download) ──
export HF_HOME="${HF_HOME:-$WORK_DIR/.cache/huggingface}"

# ── Mode-specific settings ────────────────────────────────────
if [[ "$MODE" == "test" ]]; then
    # Quick test: 6 fig3 images, 2 layers, top_n=5, no sharding
    GEN_ARGS="--test_fig3"
    DESC_FILE="results/generated_descriptions/generated_descriptions_fig3_liuhaotian.json"
    CLASSIFY_ARGS="--num_images 6 --top_n 5 --layer_start 0 --layer_end 2"
    OUT_SUFFIX="_test"
    MODE_DIR="test"
    SHARDS_EFFECTIVE=1   # no sharding in test mode
else
    # Full run: sharded across GPUs
    GEN_ARGS=""
    _DS="${DESC_SUFFIX_USER-${OUT_SUFFIX_USER}}"
    DESC_FILE="results/generated_descriptions/generated_descriptions${_DS}.json"
    CLASSIFY_ARGS=""
    OUT_SUFFIX="${OUT_SUFFIX_USER}"
    MODE_DIR="full"
    SHARDS_EFFECTIVE=$SHARDS
fi

# For step cn: can't exceed 32 layers
CLASSIFY_SHARDS=$SHARDS_EFFECTIVE
if (( CLASSIFY_SHARDS > N_LAYERS )); then
    CLASSIFY_SHARDS=$N_LAYERS
fi

# ── LSF helpers ──────────────────────────────────────────────
# Check if a job is currently PEND or RUN in LSF
is_job_active() {
    local name=$1
    bjobs -J "$name" -noheader 2>/dev/null | grep -qE "PEND|RUN"
}

# Check if a job is specifically PEND (not yet running)
is_job_pending() {
    local name=$1
    bjobs -J "$name" -noheader 2>/dev/null | grep -q "PEND"
}

# Submit a GPU job with tiered gmem escalation.
# Usage: bsub_tiered <bsub_args...> -- <command>
# Submits at GPU_GMEM_TIERS[0], then spawns a background monitor that
# re-submits at the next tier if the job is still PEND after GMEM_WAIT seconds.
bsub_tiered() {
    # Split args at '--' into bsub_args and cmd
    local bsub_args=()
    local cmd=""
    local job_name=""
    local log_file="" err_file=""
    while [[ $# -gt 0 ]]; do
        if [[ "$1" == "--" ]]; then
            shift; cmd="$*"; break
        fi
        # capture -J value for job name
        if [[ "$1" == "-J" ]]; then
            bsub_args+=("$1"); shift
            job_name="$1"
            bsub_args+=("$1"); shift
            continue
        fi
        # capture -oo/-eo paths for log clearing
        if [[ "$1" == "-oo" ]]; then
            bsub_args+=("$1"); shift
            log_file="$1"
            bsub_args+=("$1"); shift
            continue
        fi
        if [[ "$1" == "-eo" ]]; then
            bsub_args+=("$1"); shift
            err_file="$1"
            bsub_args+=("$1"); shift
            continue
        fi
        bsub_args+=("$1"); shift
    done

    # Clear previous logs so they don't accumulate across runs
    [[ -n "$log_file" ]] && rm -f "$log_file"
    [[ -n "$err_file" ]] && rm -f "$err_file"

    local n_tiers=${#GPU_GMEM_TIERS[@]}
    local first_gmem="${GPU_GMEM_TIERS[0]}"

    # Submit at first tier
    bsub "${bsub_args[@]}" -gpu "num=1:gmem=$first_gmem" -R "$GPU_RES_BASE" "$cmd"

    # If only one tier, no escalation needed
    if (( n_tiers <= 1 )); then
        return
    fi

    # Spawn background escalation monitor
    (
        set +e  # don't exit on bkill/bjobs failures
        for ((t=1; t<n_tiers; t++)); do
            sleep "$GMEM_WAIT"
            # Check if still pending
            if is_job_pending "$job_name"; then
                next_gmem="${GPU_GMEM_TIERS[$t]}"
                echo "  [escalate] $job_name still PEND after ${GMEM_WAIT}s → resubmit gmem=$next_gmem"
                bkill -J "$job_name" 2>/dev/null || true
                sleep 2  # let LSF process the kill
                bsub "${bsub_args[@]}" -gpu "num=1:gmem=$next_gmem" -R "$GPU_RES_BASE" "$cmd"
            else
                # Job is running or done, stop escalating
                break
            fi
        done
    ) &
}

# Counters
SUBMITTED=0
SKIPPED=0
MERGE_SUBMITTED=0             # 1 if merge job was submitted this run
CLS_SUBMITTED_JOBS_ALL=""      # space-separated list of cn job names for merge_nc deps

OUTPUT_DIR="${OUTPUT_DIR_USER:-results/taxonomy/${MODE_DIR}}"

# ── Banner ────────────────────────────────────────────────────
echo ""
echo "═══════════════════════════════════════════════════════════"
echo "  Xu et al. Neuron Classification Pipeline"
echo "═══════════════════════════════════════════════════════════"
echo "  Mode:               $MODE"
echo "  Backend:            $MODEL_TYPE"
echo "  Model path:         $MODEL_PATH"
echo "  Step:               $STEP"
echo "  GPUs:               $SHARDS_EFFECTIVE"
echo "  Classify shards:    $CLASSIFY_SHARDS (max $N_LAYERS layers)"
echo "  Local:              $LOCAL"
echo "  Queue:              $QUEUE"
echo "  Work dir:           $WORK_DIR"
echo "  GPU gmem tiers:     ${GPU_GMEM_TIERS[*]} (wait ${GMEM_WAIT}s between)"
echo "  Desc file:          $DESC_FILE"
echo "  Output dir:         $OUTPUT_DIR"
echo "  Ablation script:    $ABLATION_SCRIPT"
echo "  Prune images:       $PRUNE_IMAGES"
echo "  Ablation parallel:  $ABLATION_ALL (--ablation-all for 18 parallel GPU jobs)"
echo "  Idempotent:         yes (skips completed/active jobs)"
echo "═══════════════════════════════════════════════════════════"

# Create directories (no log cleanup — needed for completion detection)
mkdir -p "$WORK_DIR/results/shards"
mkdir -p "$WORK_DIR/logs"

# ═══════════════════════════════════════════════════════════════
# STEP gd: Generate descriptions (sharded by image range)
# ═══════════════════════════════════════════════════════════════
if [[ "$STEP" == "gd" || "$STEP" == "all" ]]; then

echo ""
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "  STEP gd: Generate descriptions"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

if [[ "$MODE" == "test" ]]; then
    JOB_NAME="gen_desc_test"
    echo ""
    echo "  ── generate_descriptions --test_fig3 ──"
    # Skip if test description file exists or job is active
    if [[ -s "$DESC_FILE" ]] || is_job_active "$JOB_NAME"; then
        echo "  [skip] $JOB_NAME — already done or active"
        SKIPPED=$((SKIPPED + 1))
    elif $LOCAL; then
        (cd "$WORK_DIR" && uv run python code/generate_descriptions.py \
            --original_model_path "$MODEL_PATH" $GEN_ARGS) \
            2>&1 | tee "logs/${JOB_NAME}.log"
    else
        bsub_tiered -q $QUEUE \
             -J "$JOB_NAME" \
             -oo "$WORK_DIR/logs/${JOB_NAME}.log" \
             -eo "$WORK_DIR/logs/${JOB_NAME}.err" \
             -- "cd $WORK_DIR && uv run python code/generate_descriptions.py \
                     --original_model_path $MODEL_PATH $GEN_ARGS"
        echo "  → Job: $JOB_NAME (1 GPU, tiers: ${GPU_GMEM_TIERS[*]})"
        SUBMITTED=$((SUBMITTED + 1))
    fi
else
    # Full mode: shard across GPUs
    echo ""
    echo "  ── generate_descriptions — $SHARDS_EFFECTIVE shards ──"
    echo "  Images per shard: ~$((N_TOTAL_IMAGES / SHARDS_EFFECTIVE))"

    GEN_SUBMITTED_JOBS=()  # track which shard jobs were submitted this run
    for ((s=0; s<SHARDS_EFFECTIVE; s++)); do
        START_IDX=$((s * N_TOTAL_IMAGES / SHARDS_EFFECTIVE))
        END_IDX=$(((s + 1) * N_TOTAL_IMAGES / SHARDS_EFFECTIVE))
        JOB_NAME="gen_${s}"
        SHARD_FILE="results/generated_descriptions/shards/gen_desc${_DS}_shard${s}.json"

        # Skip if shard output exists or job is active
        if [[ -s "$SHARD_FILE" ]] || is_job_active "$JOB_NAME"; then
            echo "  [skip] Shard $s ($JOB_NAME) — already done or active"
            SKIPPED=$((SKIPPED + 1))
            continue
        fi
        if $LOCAL; then
            echo "  Shard $s: images [$START_IDX, $END_IDX) → $SHARD_FILE"
            (cd "$WORK_DIR" && uv run python code/generate_descriptions.py \
                --original_model_path "$MODEL_PATH" \
                --output_path "$SHARD_FILE" \
                --start_idx $START_IDX \
                --end_idx $END_IDX) \
                2>&1 | tee "logs/${JOB_NAME}.log"
        else
            bsub_tiered -q $QUEUE \
                 -J "$JOB_NAME" \
                 -oo "$WORK_DIR/logs/${JOB_NAME}.log" \
                 -eo "$WORK_DIR/logs/${JOB_NAME}.err" \
                 -- "cd $WORK_DIR && uv run python code/generate_descriptions.py \
                     --original_model_path $MODEL_PATH \
                     --output_path $SHARD_FILE \
                     --start_idx $START_IDX \
                     --end_idx $END_IDX"
            echo "  → Shard $s: [$START_IDX, $END_IDX) tiers: ${GPU_GMEM_TIERS[*]} → $JOB_NAME"
            GEN_SUBMITTED_JOBS+=("$JOB_NAME")
            SUBMITTED=$((SUBMITTED + 1))
        fi
    done

    # ── Merge shards into single file ─────────────────────────
    MERGE_JOB="merge_gd"
    MERGE_CMD="uv run python -c \"
import json, glob, os
merged = {}
for f in sorted(glob.glob('results/generated_descriptions/shards/gen_desc${_DS}_shard*.json')):
    with open(f) as fp:
        merged.update(json.load(fp))
os.makedirs(os.path.dirname('${DESC_FILE}'), exist_ok=True)
with open('${DESC_FILE}', 'w') as fp:
    json.dump(merged, fp, indent=2)
n_shards = len(glob.glob('results/generated_descriptions/shards/gen_desc${_DS}_shard*.json'))
print(f'Merged {len(merged)} descriptions from {n_shards} shards → ${DESC_FILE}')
\""

    echo ""
    echo "  ── Merge → $DESC_FILE ──"

    # Skip if merged file exists or job is active
    if [[ -s "$DESC_FILE" ]] || is_job_active "$MERGE_JOB"; then
        echo "  [skip] $MERGE_JOB — already done or active"
        SKIPPED=$((SKIPPED + 1))
    elif $LOCAL; then
        (cd "$WORK_DIR" && eval $MERGE_CMD) 2>&1 | tee "logs/${MERGE_JOB}.log"
    else
        # Build dependency on ALL active gen jobs (submitted this run OR still running)
        BSUB_MERGE_ARGS=(-q "$QUEUE" \
             -J "$MERGE_JOB" \
             -oo "$WORK_DIR/logs/${MERGE_JOB}.log" \
             -eo "$WORK_DIR/logs/${MERGE_JOB}.err")
        DEP_PARTS=""
        for ((gs=0; gs<SHARDS_EFFECTIVE; gs++)); do
            gn="gen_${gs}"
            if is_job_active "$gn"; then
                if [[ -n "$DEP_PARTS" ]]; then
                    DEP_PARTS="$DEP_PARTS && done($gn)"
                else
                    DEP_PARTS="done($gn)"
                fi
            fi
        done
        if [[ -n "$DEP_PARTS" ]]; then
            BSUB_MERGE_ARGS+=(-w "$DEP_PARTS")
            echo "  → Job: $MERGE_JOB (depends on ${#GEN_SUBMITTED_JOBS[@]} shard jobs)"
        else
            echo "  → Job: $MERGE_JOB (no deps — all shards already done)"
        fi
        rm -f "$WORK_DIR/logs/${MERGE_JOB}.log" "$WORK_DIR/logs/${MERGE_JOB}.err"
        bsub "${BSUB_MERGE_ARGS[@]}" "cd $WORK_DIR && $MERGE_CMD"
        MERGE_SUBMITTED=1
        SUBMITTED=$((SUBMITTED + 1))
    fi
fi

fi  # end step gd

# ═══════════════════════════════════════════════════════════════
# STEP merge_gd: Merge generated description shards
# ═══════════════════════════════════════════════════════════════
if [[ "$STEP" == "merge_gd" ]]; then

echo ""
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "  STEP merge_gd: Merge generated description shards"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

MERGE_CMD="uv run python -c \"
import json, glob, os
merged = {}
for f in sorted(glob.glob('results/generated_descriptions/shards/gen_desc${_DS}_shard*.json')):
    with open(f) as fp:
        merged.update(json.load(fp))
os.makedirs(os.path.dirname('${DESC_FILE}'), exist_ok=True)
with open('${DESC_FILE}', 'w') as fp:
    json.dump(merged, fp, indent=2)
n_shards = len(glob.glob('results/generated_descriptions/shards/gen_desc${_DS}_shard*.json'))
print(f'Merged {len(merged)} descriptions from {n_shards} shards → ${DESC_FILE}')
\""

echo ""
echo "  ── Merging → $DESC_FILE ──"
(cd "$WORK_DIR" && eval $MERGE_CMD) 2>&1 | tee "logs/merge_gd.log"

fi  # end step merge_gd

# ═══════════════════════════════════════════════════════════════
# STEP cn: Classify neurons (sharded by layer range)
# ═══════════════════════════════════════════════════════════════
if [[ "$STEP" == "cn" || "$STEP" == "all" ]]; then

echo ""
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "  STEP cn: Classify neurons"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

if [[ "$MODE" == "test" ]]; then
    # Test mode: single job
    JOB_NAME="classify${OUT_SUFFIX}_test"
    STATS_FILE="$OUTPUT_DIR/$MODEL_NAME/llm/classification_stats_layers0-2.json"
    echo ""
    echo "  ── $CLASSIFY_SCRIPT — test mode ──"

    # Skip if stats file exists or job is active
    if [[ -s "$STATS_FILE" ]] || is_job_active "$JOB_NAME"; then
        echo "  [skip] $JOB_NAME — already done or active"
        SKIPPED=$((SKIPPED + 1))
    elif $LOCAL; then
        (cd "$WORK_DIR" && uv run python $CLASSIFY_SCRIPT \
            --model_type "$MODEL_TYPE" \
            --original_model_path "$MODEL_PATH" \
            --text_source generated \
            --generated_desc_path "$DESC_FILE" \
            --output_dir "$OUTPUT_DIR" \
            $CLASSIFY_ARGS) \
            2>&1 | tee "logs/${JOB_NAME}.log"
    else
        BSUB_ARGS=(-q "$QUEUE" \
            -J "$JOB_NAME" \
            -oo "$WORK_DIR/logs/${JOB_NAME}.log" \
            -eo "$WORK_DIR/logs/${JOB_NAME}.err")
        if [[ "$STEP" == "all" ]] && is_job_active "gen_desc_test"; then
            BSUB_ARGS+=(-w "done(gen_desc_test)")
        fi
        bsub_tiered "${BSUB_ARGS[@]}" \
            -- "cd $WORK_DIR && uv run python $CLASSIFY_SCRIPT \
                --model_type $MODEL_TYPE \
                --original_model_path $MODEL_PATH \
                --text_source generated \
                --generated_desc_path $DESC_FILE \
                --output_dir $OUTPUT_DIR \
                $CLASSIFY_ARGS"
        echo "  → Job: $JOB_NAME (tiers: ${GPU_GMEM_TIERS[*]})"
        SUBMITTED=$((SUBMITTED + 1))
    fi
else
    # Full mode: shard by layer range
    echo ""
    echo "  ── $CLASSIFY_SCRIPT — $CLASSIFY_SHARDS shards ──"
    echo "  Layers per shard: ~$((N_LAYERS / CLASSIFY_SHARDS))"

    CLS_SUBMITTED_JOBS=()
    for ((s=0; s<CLASSIFY_SHARDS; s++)); do
        LAYER_START=$((s * N_LAYERS / CLASSIFY_SHARDS))
        LAYER_END=$(((s + 1) * N_LAYERS / CLASSIFY_SHARDS))
        JOB_NAME="cls${OUT_SUFFIX}_${s}"
        STATS_FILE="$OUTPUT_DIR/$MODEL_NAME/llm/classification_stats_layers${LAYER_START}-${LAYER_END}.json"

        # Skip if stats file exists or job is active
        if [[ -s "$STATS_FILE" ]] || is_job_active "$JOB_NAME"; then
            echo "  [skip] Shard $s ($JOB_NAME) layers [$LAYER_START, $LAYER_END) — already done or active"
            SKIPPED=$((SKIPPED + 1))
            continue
        fi
        if $LOCAL; then
            echo "  Shard $s: layers [$LAYER_START, $LAYER_END) → $OUTPUT_DIR"
            (cd "$WORK_DIR" && uv run python $CLASSIFY_SCRIPT \
                --model_type "$MODEL_TYPE" \
                --original_model_path "$MODEL_PATH" \
                --text_source generated \
                --generated_desc_path "$DESC_FILE" \
                --output_dir "$OUTPUT_DIR" \
                --layer_start $LAYER_START \
                --layer_end $LAYER_END) \
                2>&1 | tee "logs/${JOB_NAME}.log"
        else
            # Depend on merge job only if it was submitted this run
            BSUB_ARGS=(-q "$QUEUE" \
                -J "$JOB_NAME" \
                -oo "$WORK_DIR/logs/${JOB_NAME}.log" \
                -eo "$WORK_DIR/logs/${JOB_NAME}.err")
            if [[ "$STEP" == "all" ]] && { [[ "$MERGE_SUBMITTED" == "1" ]] || is_job_active "merge_gd"; }; then
                BSUB_ARGS+=(-w "done(merge_gd)")
            fi

            bsub_tiered "${BSUB_ARGS[@]}" \
                -- "cd $WORK_DIR && uv run python $CLASSIFY_SCRIPT \
                    --model_type $MODEL_TYPE \
                    --original_model_path $MODEL_PATH \
                    --text_source generated \
                    --generated_desc_path $DESC_FILE \
                    --output_dir $OUTPUT_DIR \
                    --layer_start $LAYER_START \
                    --layer_end $LAYER_END"
            echo "  → Shard $s: layers [$LAYER_START, $LAYER_END) tiers: ${GPU_GMEM_TIERS[*]} → $JOB_NAME"
            CLS_SUBMITTED_JOBS+=("$JOB_NAME")
            SUBMITTED=$((SUBMITTED + 1))
        fi
    done

    CLS_SUBMITTED_JOBS_ALL="${CLS_SUBMITTED_JOBS[*]}"
fi

fi  # end step cn

# ═══════════════════════════════════════════════════════════════
# STEP merge_nc: Merge per-shard classification results
# ═══════════════════════════════════════════════════════════════
if [[ "$STEP" == "merge_nc" || "$STEP" == "all" ]]; then

echo ""
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "  STEP merge_nc: Merge classification results"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

MERGE_NC_CMD="cd $WORK_DIR && uv run python $CLASSIFY_SCRIPT \
    --merge \
    --model_type $MODEL_TYPE \
    --output_dir $OUTPUT_DIR"

echo ""
echo "  ── Merging → $OUTPUT_DIR ──"

if $LOCAL || [[ "$STEP" == "merge_nc" ]]; then
    # Run inline (local mode or standalone merge_nc)
    (cd "$WORK_DIR" && uv run python $CLASSIFY_SCRIPT \
        --merge \
        --model_type "$MODEL_TYPE" \
        --output_dir "$OUTPUT_DIR")
else
    # Submit as LSF job dependent on all cn jobs
    MERGE_NC_JOB="merge_nc${OUT_SUFFIX}"
    BSUB_MERGE_NC_ARGS=(-q "$QUEUE" \
        -J "$MERGE_NC_JOB" \
        -oo "$WORK_DIR/logs/${MERGE_NC_JOB}.log" \
        -eo "$WORK_DIR/logs/${MERGE_NC_JOB}.err")
    # Build dependency on ALL active cn jobs (submitted this run OR still running)
    if [[ -n "${CLS_SUBMITTED_JOBS_ALL:-}" ]]; then
        DEP_PARTS=""
        for jn in $CLS_SUBMITTED_JOBS_ALL; do
            if [[ -n "$DEP_PARTS" ]]; then
                DEP_PARTS="$DEP_PARTS && done($jn)"
            else
                DEP_PARTS="done($jn)"
            fi
        done
        BSUB_MERGE_NC_ARGS+=(-w "$DEP_PARTS")
        echo "  → Job: $MERGE_NC_JOB (depends on cn jobs)"
    else
        # Check for any active cls jobs from previous runs
        DEP_PARTS=""
        for ((cs=0; cs<CLASSIFY_SHARDS; cs++)); do
            cn="cls${OUT_SUFFIX}_${cs}"
            if is_job_active "$cn"; then
                if [[ -n "$DEP_PARTS" ]]; then
                    DEP_PARTS="$DEP_PARTS && done($cn)"
                else
                    DEP_PARTS="done($cn)"
                fi
            fi
        done
        if [[ -n "$DEP_PARTS" ]]; then
            BSUB_MERGE_NC_ARGS+=(-w "$DEP_PARTS")
            echo "  → Job: $MERGE_NC_JOB (depends on active cls jobs from previous run)"
        else
            echo "  → Job: $MERGE_NC_JOB (no deps — all cn jobs already done)"
        fi
    fi
    rm -f "$WORK_DIR/logs/${MERGE_NC_JOB}.log" "$WORK_DIR/logs/${MERGE_NC_JOB}.err"
    bsub "${BSUB_MERGE_NC_ARGS[@]}" "$MERGE_NC_CMD"
    SUBMITTED=$((SUBMITTED + 1))
fi

fi  # end step merge_nc

# ═══════════════════════════════════════════════════════════════
# STEP prune: Ablation validation of neuron taxonomy
# ═══════════════════════════════════════════════════════════════
if [[ "$STEP" == "prune" || "$STEP" == "all" ]]; then

echo ""
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "  STEP prune: Ablation validation"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

# Labels always live under full-mode classification output, regardless of ablation mode
LABELS_BASE="${OUTPUT_DIR_USER:-results/taxonomy/full}"
ABLATION_OUT="$OUTPUT_DIR/$MODEL_NAME/ablation"

if [[ "$MODE" == "test" ]]; then
    BASE_PRUNE_ARGS="--num_images 5 --conditions baseline ablate_vis ablate_text random --pope_num_questions 3"
    PRUNE_IMAGES_EFF=5
    CHAIR_NUM_IMAGES=2
else
    BASE_PRUNE_ARGS="--num_images $PRUNE_IMAGES --conditions baseline ablate_vis ablate_text random"
    PRUNE_IMAGES_EFF=$PRUNE_IMAGES
fi

# Append POPE args
if [[ -n "$POPE_PATH" ]]; then
    BASE_PRUNE_ARGS="$BASE_PRUNE_ARGS --pope_path $POPE_PATH"
    if [[ -n "$POPE_IMG_DIR" ]]; then
        BASE_PRUNE_ARGS="$BASE_PRUNE_ARGS --pope_img_dir $POPE_IMG_DIR"
    fi
fi

# Append CHAIR args
if [[ -n "$CHAIR_ANN_PATH" ]]; then
    BASE_PRUNE_ARGS="$BASE_PRUNE_ARGS --chair_ann_path $CHAIR_ANN_PATH --chair_num_images $CHAIR_NUM_IMAGES"
    if [[ -n "$POPE_IMG_DIR" ]]; then
        BASE_PRUNE_ARGS="$BASE_PRUNE_ARGS --chair_img_dir $POPE_IMG_DIR"
    fi
fi

# ── Helper: submit one ablation job ──
# Usage: submit_ablation_job <job_suffix> <output_subdir> <extra_args> <labels_dir> <label_source>
submit_ablation_job() {
    local JOB_SUFFIX="$1"
    local OUT_SUBDIR="$2"
    local EXTRA_ARGS="$3"
    local _LABELS_DIR="$4"
    local _LABEL_SOURCE="$5"
    local JOB_NAME="prune_${JOB_SUFFIX}${OUT_SUFFIX}"
    local JOB_OUT="${ABLATION_OUT}/${OUT_SUBDIR}"
    local JOB_SUMMARY="${JOB_OUT}/ablation_summary.json"
    local FULL_ARGS="$BASE_PRUNE_ARGS $EXTRA_ARGS"

    # Skip if summary exists or job is active
    if [[ -s "$JOB_SUMMARY" ]] || is_job_active "$JOB_NAME"; then
        echo "  [skip] $JOB_NAME — already done or active"
        SKIPPED=$((SKIPPED + 1))
        return
    fi

    echo "  → $JOB_NAME → $JOB_OUT  [${_LABEL_SOURCE}]"

    # Clear previous logs so they don't accumulate across runs
    rm -f "$WORK_DIR/logs/${JOB_NAME}.log" "$WORK_DIR/logs/${JOB_NAME}.err"

    if $LOCAL; then
        (cd "$WORK_DIR" && uv run python $ABLATION_SCRIPT \
            --model_type "$MODEL_TYPE" \
            --original_model_path "$MODEL_PATH" \
            --labels_dir "$_LABELS_DIR" \
            --label_source "$_LABEL_SOURCE" \
            --output_dir "$JOB_OUT" \
            $FULL_ARGS) \
            2>&1 | tee "logs/${JOB_NAME}.log"
    else
        local BSUB_ARGS=(-q "$QUEUE" \
            -J "$JOB_NAME" \
            -oo "$WORK_DIR/logs/${JOB_NAME}.log" \
            -eo "$WORK_DIR/logs/${JOB_NAME}.err")
        if [[ "$STEP" == "all" ]] && is_job_active "merge_nc${OUT_SUFFIX}"; then
            BSUB_ARGS+=(-w "done(merge_nc${OUT_SUFFIX})")
        fi
        bsub_tiered "${BSUB_ARGS[@]}" \
            -- "cd $WORK_DIR && uv run python $ABLATION_SCRIPT \
                --model_type $MODEL_TYPE \
                --original_model_path $MODEL_PATH \
                --labels_dir $_LABELS_DIR \
                --label_source $_LABEL_SOURCE \
                --output_dir $JOB_OUT \
                $FULL_ARGS"
        SUBMITTED=$((SUBMITTED + 1))
    fi
}

# ══════════════════════════════════════════════════════════════
# --ablation-all: submit all approaches × both taxonomies
#   = 9 approaches × 2 taxonomies = 18 parallel GPU jobs (noise disabled)
# ══════════════════════════════════════════════════════════════
if $ABLATION_ALL; then

# Define both taxonomy sources
TAXONOMY_CONFIGS=(
    "xu|llm_fixed_threshold|ft"
    "pmbt|llm_pmbt|perm"
)
# Format: label_source|subdir_name|short_prefix

echo ""
echo "  ── PARALLEL MODE: 9 approaches × 2 taxonomies = 18 GPU jobs ──"
echo "  Base:    $ABLATION_OUT"
echo "  POPE:    ${POPE_PATH:-none}"
echo "  CHAIR:   ${CHAIR_ANN_PATH:-none} ($CHAIR_NUM_IMAGES images)"

for TAXCFG in "${TAXONOMY_CONFIGS[@]}"; do
    IFS='|' read -r TAX_SOURCE TAX_SUBDIR TAX_PREFIX <<< "$TAXCFG"
    TAX_LABELS_DIR="$LABELS_BASE/$MODEL_NAME/$TAX_SUBDIR"

    echo ""
    echo "  ── Taxonomy: ${TAX_SOURCE} (${TAX_LABELS_DIR}) ──"

    # 1. Standard zero ablation (all neurons of each type)
    submit_ablation_job "${TAX_PREFIX}_standard" "${TAX_PREFIX}/1_standard" \
        "--ablation_method zero" "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 2. Ablation curve with label-confidence ranking
    submit_ablation_job "${TAX_PREFIX}_curve_label" "${TAX_PREFIX}/2_curve_label" \
        "--ablation_method zero --curve --curve_steps $ABLATION_CURVE_STEPS --ranking_method label" \
        "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 3. Ablation curve with CETT ranking
    submit_ablation_job "${TAX_PREFIX}_curve_cett" "${TAX_PREFIX}/3_curve_cett" \
        "--ablation_method zero --curve --curve_steps $ABLATION_CURVE_STEPS --ranking_method cett --n_cett_images $ABLATION_N_CETT" \
        "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 4. Layer-specific: early layers 0-10
    submit_ablation_job "${TAX_PREFIX}_layer_0_10" "${TAX_PREFIX}/4_layer_0_10" \
        "--ablation_method zero --layer_range 0-10" "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 5. Layer-specific: middle layers 11-21
    submit_ablation_job "${TAX_PREFIX}_layer_11_21" "${TAX_PREFIX}/5_layer_11_21" \
        "--ablation_method zero --layer_range 11-21" "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 6. Layer-specific: late layers 22-31
    submit_ablation_job "${TAX_PREFIX}_layer_22_31" "${TAX_PREFIX}/6_layer_22_31" \
        "--ablation_method zero --layer_range 22-31" "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 7. Mean ablation
    submit_ablation_job "${TAX_PREFIX}_mean" "${TAX_PREFIX}/7_mean" \
        "--ablation_method mean --n_stats_images $ABLATION_N_STATS" \
        "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 8. Noise ablation — DISABLED
    # Noise generates fresh random samples per neuron × position × forward pass,
    # making it ~20-40x slower than mean/clamp (which use a constant replacement).
    # Test mode takes ~40 min per job; full dataset would take days.
    # Mean ablation already answers the key question: does the input-specific
    # signal matter, or is any activation sufficient? Noise only refines this
    # to "generic constant vs generic random" — a subtle distinction unlikely
    # to affect conclusions. Can be re-enabled if a reviewer requests it.
    # submit_ablation_job "${TAX_PREFIX}_noise" "${TAX_PREFIX}/8_noise" \
    #     "--ablation_method noise --n_stats_images $ABLATION_N_STATS" \
    #     "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 9. Clamp high (95th percentile)
    submit_ablation_job "${TAX_PREFIX}_clamp" "${TAX_PREFIX}/9_clamp_high" \
        "--ablation_method clamp_high --n_stats_images $ABLATION_N_STATS" \
        "$TAX_LABELS_DIR" "$TAX_SOURCE"

    # 10. Top-N only (500 most confident neurons)
    submit_ablation_job "${TAX_PREFIX}_top500" "${TAX_PREFIX}/10_top_n_500" \
        "--ablation_method zero --top_n 500" "$TAX_LABELS_DIR" "$TAX_SOURCE"

done

echo ""
echo "  Total: up to 18 parallel GPU jobs (9 approaches × 2 taxonomies, noise disabled)"

# ══════════════════════════════════════════════════════════════
# Single approach mode (default, backwards-compatible)
# ══════════════════════════════════════════════════════════════
else

# Build advanced args for single-job mode
PRUNE_ARGS="$BASE_PRUNE_ARGS --ablation_method $ABLATION_METHOD"
PRUNE_ARGS="$PRUNE_ARGS --n_stats_images $ABLATION_N_STATS"
PRUNE_ARGS="$PRUNE_ARGS --ranking_method $ABLATION_RANKING"
PRUNE_ARGS="$PRUNE_ARGS --n_cett_images $ABLATION_N_CETT"

if $ABLATION_CURVE; then
    PRUNE_ARGS="$PRUNE_ARGS --curve --curve_steps $ABLATION_CURVE_STEPS"
fi
if [[ -n "$ABLATION_TOP_N" ]]; then
    PRUNE_ARGS="$PRUNE_ARGS --top_n $ABLATION_TOP_N"
fi
if [[ -n "$ABLATION_LAYER_RANGE" ]]; then
    PRUNE_ARGS="$PRUNE_ARGS --layer_range $ABLATION_LAYER_RANGE"
fi

JOB_NAME="prune${OUT_SUFFIX}"
LABELS_DIR="$LABELS_BASE/$MODEL_NAME/llm_fixed_threshold"
ABLATION_SUMMARY="$ABLATION_OUT/ablation_summary.json"
echo ""
echo "  ── $ABLATION_SCRIPT — $PRUNE_IMAGES_EFF images ──"
echo "  Labels:    $LABELS_DIR"
echo "  Output:    $ABLATION_OUT"
echo "  Method:    $ABLATION_METHOD"
echo "  Ranking:   $ABLATION_RANKING"
echo "  Curve:     $ABLATION_CURVE  (steps: $ABLATION_CURVE_STEPS)"
echo "  Top-N:     ${ABLATION_TOP_N:-all}"
echo "  Layers:    ${ABLATION_LAYER_RANGE:-all}"
if [[ -n "$POPE_PATH" ]]; then
    echo "  POPE:      $POPE_PATH"
fi
if [[ -n "$CHAIR_ANN_PATH" ]]; then
    echo "  CHAIR:     $CHAIR_ANN_PATH ($CHAIR_NUM_IMAGES images)"
fi

# Skip if summary file exists or job is active
if [[ -s "$ABLATION_SUMMARY" ]] || is_job_active "$JOB_NAME"; then
    echo "  [skip] $JOB_NAME — already done or active"
    SKIPPED=$((SKIPPED + 1))
elif $LOCAL; then
    rm -f "logs/${JOB_NAME}.log" "logs/${JOB_NAME}.err"
    (cd "$WORK_DIR" && uv run python $ABLATION_SCRIPT \
        --model_type "$MODEL_TYPE" \
        --original_model_path "$MODEL_PATH" \
        --labels_dir "$LABELS_DIR" \
        --label_source xu \
        --output_dir "$ABLATION_OUT" \
        $PRUNE_ARGS) \
        2>&1 | tee "logs/${JOB_NAME}.log"
else
    rm -f "$WORK_DIR/logs/${JOB_NAME}.log" "$WORK_DIR/logs/${JOB_NAME}.err"
    BSUB_ARGS=(-q "$QUEUE" \
        -J "$JOB_NAME" \
        -oo "$WORK_DIR/logs/${JOB_NAME}.log" \
        -eo "$WORK_DIR/logs/${JOB_NAME}.err")
    if [[ "$STEP" == "all" ]] && is_job_active "merge_nc${OUT_SUFFIX}"; then
        BSUB_ARGS+=(-w "done(merge_nc${OUT_SUFFIX})")
    fi

    bsub_tiered "${BSUB_ARGS[@]}" \
        -- "cd $WORK_DIR && uv run python $ABLATION_SCRIPT \
            --model_type $MODEL_TYPE \
            --original_model_path $MODEL_PATH \
            --labels_dir $LABELS_DIR \
            --label_source xu \
            --output_dir $ABLATION_OUT \
            $PRUNE_ARGS"
    echo "  → Job: $JOB_NAME (tiers: ${GPU_GMEM_TIERS[*]})"
    SUBMITTED=$((SUBMITTED + 1))
fi

fi  # end ABLATION_ALL check

fi  # end step prune

# ═══════════════════════════════════════════════════════════════
# STEP visualize: Generate Xu Figure 3-style activation visualizations
# ═══════════════════════════════════════════════════════════════
if [[ "$STEP" == "visualize" || "$STEP" == "all" ]]; then

echo ""
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
echo "  STEP visualize: Figure 3 activation visualizations"
echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"

# Data directory containing Phase 1/2 outputs
VIZ_DATA_DIR="$OUTPUT_DIR/$MODEL_NAME/llm"
VIZ_OUT_DIR="results/$MODEL_NAME/figure3/${MODE_DIR}"
VIZ_MARKER="$VIZ_OUT_DIR/done.marker"

COCO_IMG_DIR="${COCO_IMG_DIR:-/home/projects/bagon/shared/coco2017/images/train2017/}"

echo ""
echo "  ── $VIZ_SCRIPT — auto-select best per type ──"
echo "  Data dir:  $VIZ_DATA_DIR"
echo "  Output:    $VIZ_OUT_DIR"
echo "  COCO imgs: $COCO_IMG_DIR"

# Build viz args
VIZ_ARGS="--types visual text multimodal"
if $VIZ_FIG3; then
    VIZ_ARGS="--fig3"
    echo "  Mode:      --fig3 (reproduce Xu Figure 3 panels a-f)"
elif $VIZ_FIG89; then
    VIZ_ARGS="--fig89"
    echo "  Mode:      --fig89 (reproduce Xu Figures 8 & 9, two-sample panels)"
elif $VIZ_SUPPLEMENTARY; then
    VIZ_ARGS="--supplementary"
    echo "  Mode:      --supplementary (reproduce Xu Figures 15-17)"
fi

# Skip if already done or active
JOB_NAME="viz${OUT_SUFFIX}"
if [[ -f "$VIZ_MARKER" ]] || is_job_active "$JOB_NAME"; then
    echo "  [skip] $JOB_NAME — already done or active"
    SKIPPED=$((SKIPPED + 1))
elif $LOCAL; then
    # CPU-only — no GPU needed
    (cd "$WORK_DIR" && uv run python $VIZ_SCRIPT \
        --data_dir "$VIZ_DATA_DIR" \
        --coco_img_dir "$COCO_IMG_DIR" \
        --generated_desc_path "$DESC_FILE" \
        --model_type "$MODEL_TYPE" \
        --output_dir "$VIZ_OUT_DIR" \
        $VIZ_ARGS) \
        2>&1 | tee "logs/${JOB_NAME}.log"
    touch "$VIZ_MARKER"
else
    # Submit CPU job (no GPU)
    BSUB_ARGS=(-q "$QUEUE" \
        -J "$JOB_NAME" \
        -oo "$WORK_DIR/logs/${JOB_NAME}.log" \
        -eo "$WORK_DIR/logs/${JOB_NAME}.err")
    # Depend on merge_nc if it was submitted this run
    if [[ "$STEP" == "all" ]] && is_job_active "merge_nc${OUT_SUFFIX}"; then
        BSUB_ARGS+=(-w "done(merge_nc${OUT_SUFFIX})")
    fi

    rm -f "$WORK_DIR/logs/${JOB_NAME}.log" "$WORK_DIR/logs/${JOB_NAME}.err"
    bsub "${BSUB_ARGS[@]}" \
        "cd $WORK_DIR && uv run python $VIZ_SCRIPT \
            --data_dir $VIZ_DATA_DIR \
            --coco_img_dir $COCO_IMG_DIR \
            --generated_desc_path $DESC_FILE \
            --model_type $MODEL_TYPE \
            --output_dir $VIZ_OUT_DIR \
            $VIZ_ARGS \
            && touch $VIZ_MARKER"
    echo "  → Job: $JOB_NAME (CPU only, no GPU)"
    SUBMITTED=$((SUBMITTED + 1))
fi

