PLOT_DATA_DIR="$OUTPUT_DIR/$MODEL_NAME/llm"
PLOT_PMBT_DIR="$OUTPUT_DIR/$MODEL_NAME/llm_pmbt"
PLOT_OUT_DIR="results/$MODEL_NAME/figures/${MODE_DIR}"
PLOT_MARKER="$PLOT_OUT_DIR/done.marker"

echo ""
