echo "═══════════════════════════════════════════════════════════"
if $LOCAL; then
    echo "  PIPELINE COMPLETE (local mode)"
else
    echo "  SUBMITTED: $SUBMITTED   SKIPPED: $SKIPPED (already done/active)"
    if (( SUBMITTED == 0 && SKIPPED > 0 )); then
        echo ""
        echo "  All jobs already completed or running!"
    fi
    echo ""
    echo "  GPU allocation:"
    echo "    Tiers: ${GPU_GMEM_TIERS[*]} (escalate every ${GMEM_WAIT}s)"
    echo ""
    echo "  Job dependency chain:"
    if [[ "$MODE" == "test" ]]; then
        echo "    gen_desc_test → classify_test"
    else
        echo "    gen_0..N → merge_gd → cls_0..N → merge_nc → prune / visualize / plot"
    fi
