# # #!/bin/bash
# # # ═══════════════════════════════════════════════════════════════════
# # # run_pipeline.sh — Full Xu et al. neuron classification pipeline
# # #
# # # Backend: liuhaotian/llava-v1.5-7b (original LLaVA model)
# # #
# # # Chains:  gd → merge_gd → cn → merge_nc → prune / visualize / plot
# # # Keeps Python scripts separate; this script handles orchestration.
# # #
# # # Usage:
# # #   bash run_pipeline.sh                              # full pipeline, 32 GPUs
# # #   bash run_pipeline.sh --step gd                    # only generate descriptions
# # #   bash run_pipeline.sh --step cn                    # only classify (descriptions must exist)
# # #   bash run_pipeline.sh --step merge_gd              # merge generated description shards
# # #   bash run_pipeline.sh --step merge_nc              # merge per-shard classification results
# # #   bash run_pipeline.sh --step prune                 # ablation validation of taxonomy
# # #   bash run_pipeline.sh --step visualize             # generate Figure 3 visualizations (CPU only)
# # #   bash run_pipeline.sh --step visualize --viz-fig3  # reproduce exact Xu Figure 3 panels (a)-(f)
# # #   bash run_pipeline.sh --step visualize --viz-fig89 # reproduce Xu Figures 8 & 9 (two-sample)
# # #   bash run_pipeline.sh --step visualize --viz-supplementary  # reproduce Figures 15-17
# # #   bash run_pipeline.sh --step plot                          # generate Figures 5/6/7 + comparison charts
# # #   bash run_pipeline.sh --mode test                  # quick test (6 fig3 images, 2 layers, 1 GPU)
# # #   bash run_pipeline.sh --shards 16                  # use 16 GPUs
# # #   bash run_pipeline.sh --local                      # run locally (no bsub, no sharding)
# # #   bash run_pipeline.sh --queue waic-risk            # use waic-risk queue
# # #   bash run_pipeline.sh --suffix _v2                 # output to results/classification_v2
# # #   bash run_pipeline.sh --prune-images 200           # use 200 images for ablation
# # #   bash run_pipeline.sh --step prune --pope-path pope/coco_pope_random.json
# # #   bash run_pipeline.sh --step prune --pope-path pope/coco_pope_random.json \
# # #       --chair-ann-path /path/to/instances_val2014.json \
# # #       --pope-img-dir /path/to/val2014/
# # #
# # # GPU tiered escalation:
# # #   All jobs start at gmem=80G. If still PEND after 2 min, killed and
# # #   resubmitted at gmem=40G. After another 2 min → gmem=10G.
# # #   Override tiers: --gmem 80G,40G,10G   Override wait: --gmem-wait 120
# # #
# # # Idempotent: re-running skips jobs whose output already exists or
# # #             that are currently PEND/RUN in LSF.
# # #
# # # Examples:
# # #   bash run_pipeline.sh --mode test --local
# # #   bash run_pipeline.sh --shards 32
# # #   bash run_pipeline.sh --step cn --shards 32
# # # ═══════════════════════════════════════════════════════════════════

# # set -euo pipefail

# # # ── Defaults ──────────────────────────────────────────────────
# # QUEUE="waic-risk"
# # LOCAL=false
# # STEP="all"             # gd | cn | merge_gd | merge_nc | prune | visualize | plot | all
# # MODE="full"            # test | full
# # SHARDS=32              # GPUs
# # MODEL_TYPE="liuhaotian"    # model backend (liuhaotian/llava-v1.5-7b)
# # MODEL_PATH="liuhaotian/llava-v1.5-7b"  # HF Hub ID or local path to model weights
