# # # # # # # ── Mode-specific settings ────────────────────────────────────
# # # # # # if [[ "$MODE" == "test" ]]; then
# # # # # #     # Quick test: 6 fig3 images, 2 layers, top_n=5, no sharding
# # # # # #     GEN_ARGS="--test_fig3"
